import React from 'react';
import { motion } from 'framer-motion';
import { Users, Award, Shield, Clock, Phone, Mail, MapPin } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const AboutPage = () => {
  const { t } = useLanguage();
  const stats = [
    { number: '5000+', label: t('customers') || '满意客户' },
    { number: '100+', label: t('team') || '专业团队' },
    { number: '24/7', label: t('support') || '服务支持' },
    { number: '98%', label: t('satisfaction') || '客户满意度' }
  ];

  const values = [
    {
      icon: Shield,
      title: t('quality') || '质量保证',
      description: t('qualityDesc') || '我们承诺提供最高质量的服务和产品，确保您的物业得到最佳保护。'
    },
    {
      icon: Clock,
      title: t('timely') || '及时响应',
      description: t('timelyDesc') || '快速响应您的需求，提供24/7全天候服务支持。'
    },
    {
      icon: Users,
      title: t('professional') || '专业团队',
      description: t('professionalDesc') || '拥有经验丰富的专业团队，为您提供最优质的维护服务。'
    },
    {
      icon: Award,
      title: t('integrity') || '诚信经营',
      description: t('integrityDesc') || '以诚信为本，透明定价，无隐藏费用。'
    }
  ];

  const team = [
    {
      name: '张明',
      position: t('founder') || '创始人 & CEO',
      image: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=300',
      description: t('founderDesc') || '拥有15年物业管理经验，致力于为客户提供最优质的服务。'
    },
    {
      name: '李华',
      position: t('cto') || '技术总监',
      image: 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=300',
      description: t('ctoDesc') || '专注于技术创新，确保平台稳定性和用户体验。'
    },
    {
      name: '王强',
      position: t('coo') || '运营总监',
      image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=300',
      description: t('cooDesc') || '负责日常运营管理，确保服务质量达到最高标准。'
    }
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-blue-600 to-purple-600 text-white py-20">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center"
          >
            <h1 className="text-4xl md:text-5xl font-bold mb-6">
              {t('about')}
            </h1>
            <p className="text-xl mb-8 max-w-3xl mx-auto">
              {t('aboutUs')}
            </p>
          </motion.div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
            {stats.map((stat, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="text-center"
              >
                <div className="text-3xl md:text-4xl font-bold text-blue-600 mb-2">
                  {stat.number}
                </div>
                <div className="text-gray-600">{stat.label}</div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Story Section */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          <div className="grid md:grid-cols-2 gap-12 items-center">
            <motion.div
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
            >
              <h2 className="text-3xl font-bold mb-6">{t('ourStory') || '我们的故事'}</h2>
              <p className="text-gray-600 mb-4">
                Swift Fix Pro 成立于2020年，源于创始人张明对物业管理行业的深刻理解和对服务质量的执着追求。
                在过去的几年里，我们从一个小的本地服务提供商发展成为行业领先的物业维护平台。
              </p>
              <p className="text-gray-600 mb-4">
                我们的使命是通过技术创新和优质服务，为物业所有者提供便捷、可靠、高效的维护解决方案。
                我们相信，每一个物业都值得得到最好的照顾。
              </p>
              <p className="text-gray-600">
                通过我们的平台，客户可以轻松找到专业的维护服务提供商，获得透明的定价和高质量的服务。
                我们致力于成为您最值得信赖的物业维护伙伴。
              </p>
            </motion.div>
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
              className="relative"
            >
              <img
                src="https://images.unsplash.com/photo-1560472354-b33ff0c44a43?w=600"
                alt="我们的故事"
                className="rounded-lg shadow-lg"
              />
            </motion.div>
          </div>
        </div>
      </section>

      {/* Values Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center mb-12"
          >
            <h2 className="text-3xl font-bold mb-4">{t('values') || '我们的价值观'}</h2>
            <p className="text-gray-600 max-w-2xl mx-auto">
              {t('valuesDesc') || '这些核心价值观指导着我们的每一个决策和行动，确保我们始终为客户提供最优质的服务。'}
            </p>
          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
            {values.map((value, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="text-center p-6 rounded-lg bg-gray-50 hover:bg-gray-100 transition-colors"
              >
                <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 text-white rounded-full mb-4">
                  <value.icon size={24} />
                </div>
                <h3 className="text-xl font-semibold mb-3">{value.title}</h3>
                <p className="text-gray-600">{value.description}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Team Section */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center mb-12"
          >
            <h2 className="text-3xl font-bold mb-4">{t('team') || '我们的团队'}</h2>
            <p className="text-gray-600 max-w-2xl mx-auto">
              {t('teamDesc') || '我们的专业团队致力于为您提供最优质的物业维护服务，每一位成员都拥有丰富的行业经验。'}
            </p>
          </motion.div>

          <div className="grid md:grid-cols-3 gap-8">
            {team.map((member, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: index * 0.1 }}
                className="text-center"
              >
                <div className="mb-4">
                  <img
                    src={member.image}
                    alt={member.name}
                    className="w-32 h-32 rounded-full mx-auto object-cover shadow-lg"
                  />
                </div>
                <h3 className="text-xl font-semibold mb-2">{member.name}</h3>
                <p className="text-blue-600 mb-3">{member.position}</p>
                <p className="text-gray-600">{member.description}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* Contact Section */}
      <section className="py-16 bg-white">
        <div className="container mx-auto px-4">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="text-center mb-12"
          >
            <h2 className="text-3xl font-bold mb-4">{t('contactUs')}</h2>
            <p className="text-gray-600 max-w-2xl mx-auto">
              {t('contactUs')}
            </p>
          </motion.div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="text-center p-6">
              <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 text-white rounded-full mb-4">
                <Phone size={24} />
              </div>
              <h3 className="text-xl font-semibold mb-2">{t('phone') || '电话咨询'}</h3>
              <p className="text-gray-600">+65 6123 4567</p>
              <p className="text-gray-600">Mon-Sun 8:00-22:00</p>
            </div>

            <div className="text-center p-6">
              <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 text-white rounded-full mb-4">
                <Mail size={24} />
              </div>
              <h3 className="text-xl font-semibold mb-2">{t('email') || '邮件咨询'}</h3>
              <p className="text-gray-600">service@swiftfixpro.com</p>
              <p className="text-gray-600">24小时内回复</p>
            </div>

            <div className="text-center p-6">
              <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 text-white rounded-full mb-4">
                <MapPin size={24} />
              </div>
              <h3 className="text-xl font-semibold mb-2">{t('address') || '公司地址'}</h3>
              <p className="text-gray-600">新加坡</p>
              <p className="text-gray-600">CBD, 123 Main St</p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default AboutPage;
